import { Check, X } from 'lucide-react';
import './PasswordChecklist.css';

interface PasswordChecklistProps {
    password: string;
    visible: boolean;
}

export const PasswordChecklist = ({ password, visible }: PasswordChecklistProps) => {
    if (!visible) return null;

    const rules = [
        { label: '8+ characters', test: (p: string) => p.length >= 8 },
        { label: 'Uppercase letter', test: (p: string) => /[A-Z]/.test(p) },
        { label: 'Lowercase letter', test: (p: string) => /[a-z]/.test(p) },
        { label: 'Digit', test: (p: string) => /\d/.test(p) },
        { label: 'Symbol (@$!%*?&)', test: (p: string) => /[@$!%*?&]/.test(p) },
    ];

    return (
        <div className="password-checklist">
            {rules.map((rule, idx) => {
                const isValid = rule.test(password);
                return (
                    <div key={idx} className={`checklist-item ${isValid ? 'valid' : 'invalid'}`}>
                        {isValid ? <Check size={14} className="icon check-icon" /> : <X size={14} className="icon x-icon" />}
                        <span>{rule.label}</span>
                    </div>
                );
            })}
        </div>
    );
};

export const isPasswordValidComplete = (password: string) => {
    return /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/.test(password);
};

import { createContext, useContext, useState, useEffect, type ReactNode } from 'react';
import { setMemoryToken } from '../utils/tokenMemory';

interface AuthContextType {
    isAuthenticated: boolean;
    token: string | null;
    login: (token: string) => void;
    logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
    const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
    const [token, setToken] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState<boolean>(true);

    useEffect(() => {
        const checkAuth = async () => {
            try {
                setIsLoading(true);
                const response = await fetch('http://localhost:5000/api/auth/me', {
                    method: 'GET',
                    headers: { 'Content-Type': 'application/json' },
                    credentials: 'include' // Important for cookies
                });

                if (response.ok) {
                    setIsAuthenticated(true);
                    setToken('memory-auth'); // The fetch interceptor handles injecting bearer
                } else {
                    setIsAuthenticated(false);
                    setToken(null);
                }
            } catch (err) {
                console.error("Auth check failed:", err);
                setIsAuthenticated(false);
                setToken(null);
            } finally {
                setIsLoading(false);
            }
        };

        checkAuth();
    }, []);

    const login = (newToken: string) => {
        setMemoryToken(newToken);
        setToken(newToken);
        setIsAuthenticated(true);
    };

    const logout = async () => {
        try {
            await fetch('http://localhost:5000/api/auth/logout', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                credentials: 'include'
            });
        } catch (err) {
            console.error('Logout failed:', err);
        }
        setMemoryToken(null);
        localStorage.removeItem('user_info');
        setToken(null);
        setIsAuthenticated(false);
        // Hard redirect (Bug #3)
        window.location.href = '/';
    };

    if (isLoading) {
        return <div>Loading authentication...</div>;
    }

    return (
        <AuthContext.Provider value={{ isAuthenticated, token, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import { useEffect, useRef } from 'react';
import type { ViolationType } from '../types/assessment.types';

interface UseAntiCheatProps {
    isActive: boolean;
    onViolation: (type: ViolationType) => void;
}

export function useAntiCheat({ isActive, onViolation }: UseAntiCheatProps) {
    const onViolationRef = useRef(onViolation);

    useEffect(() => {
        onViolationRef.current = onViolation;
    }, [onViolation]);

    useEffect(() => {
        if (!isActive) return;

        const handleVisibilityChange = () => {
            if (document.hidden) {
                onViolationRef.current('TAB_SWITCH');
            }
        };

        const handleBlur = () => {
            onViolationRef.current('WINDOW_BLUR');
        };

        const handleFullscreenChange = () => {
            if (!document.fullscreenElement) {
                onViolationRef.current('FULLSCREEN_EXIT');
                // Attempt force re-enter after a brief pause
                setTimeout(() => {
                    document.documentElement.requestFullscreen().catch(err => {
                        console.warn("Could not auto-resume fullscreen:", err);
                    });
                }, 1000);
            }
        };

        const handleKeyDown = (e: KeyboardEvent) => {
            const blocked = [
                e.ctrlKey && ['c', 'v', 'a', 'u', 's', 'p'].includes(e.key.toLowerCase()),
                e.key === 'F12',
                e.key === 'F11',
                e.altKey && e.key === 'Tab',
                e.metaKey,
                e.ctrlKey && e.shiftKey && ['i', 'j'].includes(e.key.toLowerCase()),
            ];

            if (blocked.some(Boolean)) {
                e.preventDefault();
                e.stopPropagation();
                onViolationRef.current('KEYBOARD_SHORTCUT');
            }
        };

        const handleContextMenu = (e: MouseEvent) => {
            e.preventDefault();
            onViolationRef.current('RIGHT_CLICK');
        };

        const handleCopyState = (e: ClipboardEvent) => {
            e.preventDefault();
            onViolationRef.current('COPY_ATTEMPT');
        };

        const handleSelectStart = (_e: Event) => {
            // e.preventDefault();
            // Note: Preventing selectstart can break accessibility and legit form inputs
            // Muted unless strictly required, but usually 'COPY_ATTEMPT' is enough.
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);
        window.addEventListener('blur', handleBlur);
        document.addEventListener('fullscreenchange', handleFullscreenChange);
        document.addEventListener('keydown', handleKeyDown);
        document.addEventListener('contextmenu', handleContextMenu);

        ['copy', 'paste', 'cut'].forEach(event => {
            document.addEventListener(event, handleCopyState as EventListener);
        });

        document.addEventListener('selectstart', handleSelectStart);

        return () => {
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            window.removeEventListener('blur', handleBlur);
            document.removeEventListener('fullscreenchange', handleFullscreenChange);
            document.removeEventListener('keydown', handleKeyDown);
            document.removeEventListener('contextmenu', handleContextMenu);

            ['copy', 'paste', 'cut'].forEach(event => {
                document.removeEventListener(event, handleCopyState as EventListener);
            });
            document.removeEventListener('selectstart', handleSelectStart);
        };
    }, [isActive]);
}

import { useEffect, useRef, useState, useCallback } from 'react';

/**
 * Hook to manage sound detection context
 */
export function useSoundDetection() {
    const [audioAllowed, setAudioAllowed] = useState<boolean | null>(null);
    const audioContextRef = useRef<AudioContext | null>(null);
    const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
    const analyserRef = useRef<AnalyserNode | null>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const requestAudio = useCallback(async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            streamRef.current = stream;

            const AudioContextCls = window.AudioContext || (window as any).webkitAudioContext;
            const audioCtx = new AudioContextCls();
            audioContextRef.current = audioCtx;

            const analyser = audioCtx.createAnalyser();
            analyser.fftSize = 256;
            analyserRef.current = analyser;

            const source = audioCtx.createMediaStreamSource(stream);
            source.connect(analyser);
            sourceRef.current = source;

            setAudioAllowed(true);
            return true;
        } catch (err) {
            console.error("Audio permission denied", err);
            setAudioAllowed(false);
            return false;
        }
    }, []);

    const stopAudio = useCallback(() => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(t => t.stop());
            streamRef.current = null;
        }
        if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
            audioContextRef.current.close().catch(console.error);
        }
        setAudioAllowed(false);
    }, []);

    const checkNoiseLevel = useCallback((): boolean => {
        if (!analyserRef.current) return false;

        const analyser = analyserRef.current;
        const dataArray = new Uint8Array(analyser.frequencyBinCount);
        analyser.getByteFrequencyData(dataArray);

        // Calculate peak amplitude rather than spreading across 256 bins (which dilutes speech/music)
        const peakAmplitude = Math.max(...Array.from(dataArray));

        // Peak goes from 0 to 255. 120 is about 47% volume on a single frequency band.
        return peakAmplitude > 120;
    }, []);

    // Cleanup on unmount
    useEffect(() => {
        return stopAudio;
    }, [stopAudio]);

    return {
        audioAllowed,
        requestAudio,
        stopAudio,
        checkNoiseLevel
    };
}

import React from 'react'
import ReactDOM from 'react-dom/client'
import App from './App'
import { AuthProvider } from './context/AuthContext'
import './index.css'

import { getMemoryToken, setMemoryToken } from './utils/tokenMemory';

// Global fetch interceptor to handle 401s & auto-attach AccessToken (Bug #3 & Ticket #8)
const originalFetch = window.fetch;
let isRefreshing = false;
let refreshSubscribers: ((token: string) => void)[] = [];

const onRerefreshed = (token: string) => {
  refreshSubscribers.forEach(cb => cb(token));
  refreshSubscribers = [];
}
const addRefreshSubscriber = (cb: (token: string) => void) => {
  refreshSubscribers.push(cb);
}

window.fetch = async (...args) => {
  let [resource, config] = args;

  // Skip interceptor for refresh endpoint itself to prevent loops
  if (typeof resource === 'string' && resource.includes('/api/auth/refresh')) {
    return originalFetch(...args);
  }

  // Auto-attach Bearer token if we have one in memory
  const token = getMemoryToken();
  if (token && typeof resource === 'string' && resource.includes('/api/')) {
    config = config || {};
    config.headers = {
      ...config.headers,
      'Authorization': `Bearer ${token}`
    };
    args = [resource, config];
  }

  const response = await originalFetch(...args);

  if (response.status === 401) {
    const isLoginRoute = window.location.hash.includes('#/login') || window.location.hash === '' || window.location.hash === '#/';
    const isRegisterRoute = window.location.hash.includes('#/register');

    if (!isLoginRoute && !isRegisterRoute && !window.location.search.includes('reason=session_expired')) {

      if (!isRefreshing) {
        isRefreshing = true;
        try {
          const refreshRes = await originalFetch('http://localhost:5000/api/auth/refresh', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'include' // Send HttpOnly refresh token
          });

          if (refreshRes.ok) {
            const data = await refreshRes.json();
            setMemoryToken(data.accessToken);
            isRefreshing = false;
            onRerefreshed(data.accessToken);

            // Retry original request
            let newConfig = (config as RequestInit) || {};
            newConfig.headers = {
              ...newConfig.headers,
              'Authorization': `Bearer ${data.accessToken}`
            };
            return originalFetch(resource, newConfig);
          }
        } catch (e) {
          console.error('Token refresh failed', e);
        }

        isRefreshing = false;
        // If refresh failed:
        const userRaw = localStorage.getItem('HIRESYNC_USER');
        if (userRaw) {
          try {
            const user = JSON.parse(userRaw);
            sessionStorage.setItem('pendingRedirect', JSON.stringify({
              url: window.location.hash,
              userId: user._id,
              role: user.role
            }));
          } catch (e) { }
        }
        setMemoryToken(null);
        localStorage.clear();
        // Do not clear sessionStorage to preserve the redirect binding
        window.location.href = '/?reason=session_expired#/login';
      } else {
        // Queue this request, wait for refresh
        return new Promise(resolve => {
          addRefreshSubscriber((newToken) => {
            let newConfig = (config as RequestInit) || {};
            newConfig.headers = {
              ...newConfig.headers,
              'Authorization': `Bearer ${newToken}`
            };
            resolve(originalFetch(resource, newConfig));
          });
        });
      }
    }
  }
  return response;
};

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <AuthProvider>
      <App />
    </AuthProvider>
  </React.StrictMode>,
)

