// ÔöÇÔöÇ 3D Animated Circular Gauge ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const CircularGauge3D = ({ value }: { value: number }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const animRef = useRef<number>(0);
    const progressRef = useRef(0);
    const rotationRef = useRef(0);
    const pulseRef = useRef(0);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const dpr = window.devicePixelRatio || 1;
        const S = 210;
        canvas.width = S * dpr;
        canvas.height = S * dpr;
        canvas.style.width = S + 'px';
        canvas.style.height = S + 'px';
        ctx.scale(dpr, dpr);

        const cx = S / 2, cy = S / 2;
        const R = 78;
        const startA = -Math.PI / 2;
        const target = value / 100;

        const draw = (p: number, rot: number, pulse: number) => {
            ctx.clearRect(0, 0, S, S);

            // ÔöÇÔöÇ Depth shadow rings (3D illusion) ÔöÇÔöÇ
            const shadowOffsets = [{ dx: 3, dy: 5, alpha: 0.12 }, { dx: 2, dy: 3, alpha: 0.08 }];
            shadowOffsets.forEach(({ dx, dy, alpha }) => {
                ctx.save();
                ctx.beginPath();
                ctx.arc(cx + dx, cy + dy, R, 0, Math.PI * 2);
                ctx.strokeStyle = `rgba(59,130,246,${alpha})`;
                ctx.lineWidth = 14;
                ctx.stroke();
                ctx.restore();
            });

            // ÔöÇÔöÇ Background track (3D depth tint) ÔöÇÔöÇ
            const bgGrad = ctx.createLinearGradient(cx - R, cy - R, cx + R, cy + R);
            bgGrad.addColorStop(0, 'rgba(30,41,59,0.9)');
            bgGrad.addColorStop(1, 'rgba(15,23,42,0.9)');
            ctx.beginPath();
            ctx.arc(cx, cy, R, 0, Math.PI * 2);
            ctx.strokeStyle = bgGrad;
            ctx.lineWidth = 14;
            ctx.stroke();

            // ÔöÇÔöÇ Inner sphere shading (3D bowl) ÔöÇÔöÇ
            const sphere = ctx.createRadialGradient(cx - 20, cy - 22, 4, cx, cy, R * 0.85);
            sphere.addColorStop(0, 'rgba(59,130,246,0.05)');
            sphere.addColorStop(0.5, 'rgba(30,41,59,0.03)');
            sphere.addColorStop(1, 'rgba(0,0,0,0.2)');
            ctx.beginPath();
            ctx.arc(cx, cy, R - 7, 0, Math.PI * 2);
            ctx.fillStyle = sphere;
            ctx.fill();

            // ÔöÇÔöÇ Slow outer rotating scan ring ÔöÇÔöÇ
            const scanEnd = startA + rot;
            const scanGrad = ctx.createLinearGradient(cx - R, cy, cx + R, cy);
            scanGrad.addColorStop(0, 'rgba(139,92,246,0)');
            scanGrad.addColorStop(0.5, `rgba(139,92,246,${0.35 + pulse * 0.15})`);
            scanGrad.addColorStop(1, 'rgba(139,92,246,0)');
            ctx.beginPath();
            ctx.arc(cx, cy, R + 12, scanEnd - 0.5, scanEnd + 0.5);
            ctx.strokeStyle = scanGrad;
            ctx.lineWidth = 6;
            ctx.lineCap = 'round';
            ctx.stroke();

            // ÔöÇÔöÇ Outer pulsing glow ring ÔöÇÔöÇ
            ctx.beginPath();
            ctx.arc(cx, cy, R + 18, startA, startA + p * Math.PI * 2);
            ctx.strokeStyle = `rgba(6,182,212,${0.1 + pulse * 0.08})`;
            ctx.lineWidth = 3;
            ctx.lineCap = 'round';
            ctx.stroke();

            // ÔöÇÔöÇ Second inner depth ring ÔöÇÔöÇ
            ctx.beginPath();
            ctx.arc(cx, cy, R - 10, startA, startA + p * Math.PI * 2 * 0.9);
            ctx.strokeStyle = `rgba(99,102,241,${0.2 + pulse * 0.05})`;
            ctx.lineWidth = 3;
            ctx.lineCap = 'round';
            ctx.stroke();

            // ÔöÇÔöÇ Main arc ÔÇö premium 3 stop gradient ÔöÇÔöÇ
            const mainGrad = ctx.createLinearGradient(cx - R, cy, cx + R, cy);
            mainGrad.addColorStop(0, '#6366f1');
            mainGrad.addColorStop(0.45, '#3b82f6');
            mainGrad.addColorStop(1, '#06b6d4');
            ctx.beginPath();
            ctx.arc(cx, cy, R, startA, startA + p * Math.PI * 2);
            ctx.strokeStyle = mainGrad;
            ctx.lineWidth = 14;
            ctx.lineCap = 'round';
            ctx.shadowColor = '#3b82f6';
            ctx.shadowBlur = 22 + pulse * 8;
            ctx.stroke();
            ctx.shadowBlur = 0;

            // ÔöÇÔöÇ Bright leading tip ÔöÇÔöÇ
            if (p > 0.02) {
                const tipA = startA + p * Math.PI * 2;
                const tx = cx + Math.cos(tipA) * R;
                const ty = cy + Math.sin(tipA) * R;
                const tipGrad = ctx.createRadialGradient(tx, ty, 0, tx, ty, 10);
                tipGrad.addColorStop(0, `rgba(255,255,255,${0.8 + pulse * 0.2})`);
                tipGrad.addColorStop(0.4, 'rgba(6,182,212,0.6)');
                tipGrad.addColorStop(1, 'rgba(6,182,212,0)');
                ctx.beginPath();
                ctx.arc(tx, ty, 10, 0, Math.PI * 2);
                ctx.fillStyle = tipGrad;
                ctx.fill();
            }

            // ÔöÇÔöÇ Labels ÔöÇÔöÇ
            ctx.textAlign = 'center';

            // "OVERALL" top
            ctx.fillStyle = '#64748b';
            ctx.font = `600 10px Inter,sans-serif`;
            ctx.fillText('OVERALL', cx, cy - 26);

            // Big percentage
            ctx.fillStyle = '#ffffff';
            ctx.font = `800 40px Inter,sans-serif`;
            ctx.shadowColor = 'rgba(59,130,246,0.5)';
            ctx.shadowBlur = 12;
            const displayVal = value > 0 ? `${Math.round(p * value)}%` : 'N/A';
            ctx.fillText(displayVal, cx, cy + 14);
            ctx.shadowBlur = 0;

            // Cyan trend
            ctx.fillStyle = '#06b6d4';
            ctx.font = `600 11px Inter,sans-serif`;
            ctx.fillText(value > 0 ? '+4.2%' : '-', cx, cy + 32);
        };

        // Phase 1: fill animation, then Phase 2: continuous rotation
        let filled = false;
        const animate = () => {
            pulseRef.current = (Math.sin(Date.now() * 0.002) + 1) / 2;
            rotationRef.current += 0.008;

            if (!filled) {
                progressRef.current += (target - progressRef.current) * 0.04;
                if (Math.abs(progressRef.current - target) < 0.002) {
                    progressRef.current = target;
                    filled = true;
                }
            }

            draw(progressRef.current, rotationRef.current, pulseRef.current);
            animRef.current = requestAnimationFrame(animate);
        };

        const t = setTimeout(() => animate(), 150);
        return () => { clearTimeout(t); cancelAnimationFrame(animRef.current); };
    }, [value]);

    return <canvas ref={canvasRef} />;
};

// ÔöÇÔöÇ Data ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// SKILLS and EVENTS removed (pulled from stores)

// Fake static jobs array removed

const TOTAL_BARS = 7;

const getStreak = () => {
    try {
        const today = new Date().toDateString();
        const stored = localStorage.getItem('hiresync_login_streak');
        if (!stored) {
            localStorage.setItem('hiresync_login_streak', JSON.stringify({ streak: 1, lastLogin: today }));
            return 1;
        }
        const parsed = JSON.parse(stored);
        if (parsed.lastLogin === today) {
            return parsed.streak;
        }

        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        if (parsed.lastLogin === yesterday.toDateString()) {
            const newStreak = parsed.streak + 1;
            localStorage.setItem('hiresync_login_streak', JSON.stringify({ streak: newStreak, lastLogin: today }));
            return newStreak;
        }

        // Missed a day
        localStorage.setItem('hiresync_login_streak', JSON.stringify({ streak: 1, lastLogin: today }));
        return 1;
    } catch {
        return 1;
    }
};

