import { useState, useEffect } from 'react';
import {
    ChevronLeft, ChevronRight,
    Calendar, Zap, ArrowRight, Globe
} from 'lucide-react';
import CandidateHeader from '../components/CandidateHeader';
import { getEvents, type TechEvent, type EventCategory } from '../utils/eventStore';
import './EventsPage.css';

// ÔöÇÔöÇ Types ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
