export default EventsPage;

import { useState, useEffect, type FormEvent } from 'react';
import { Layers, Eye, EyeOff } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { setAuthUser, hydrateProfileFromAuth, getProfile } from '../utils/profileStore';
import { PasswordChecklist, isPasswordValidComplete } from '../components/PasswordChecklist';
import './Login.css';
import './portalBadge.css';

const Login = () => {
    const { login, isAuthenticated } = useAuth();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);

    const hashParams = new URLSearchParams(window.location.hash.split('?')[1] || '');
    const urlRole = hashParams.get('role');
    const [role, setRole] = useState<'candidate' | 'recruiter'>(urlRole === 'recruiter' ? 'recruiter' : 'candidate');

    const [passwordFocused, setPasswordFocused] = useState(false);

    const [errors, setErrors] = useState<{ email?: string; password?: string; auth?: string }>({});
    const [isLoading, setIsLoading] = useState(false);
    const [lockoutTimer, setLockoutTimer] = useState<number | null>(null);

    // Redirect if already authenticated
    useEffect(() => {
        if (isAuthenticated) {
            window.location.hash = 'dashboard';
        }
    }, [isAuthenticated]);

    // Countdown effect for lockout
    useEffect(() => {
        let interval: number;
        if (lockoutTimer && lockoutTimer > 0) {
            interval = window.setInterval(() => {
                setLockoutTimer((prev) => (prev && prev > 1 ? prev - 1 : null));
            }, 1000);
        }
        return () => window.clearInterval(interval);
    }, [lockoutTimer]);

    const handleSubmit = async (e: FormEvent) => {
        e.preventDefault();

        // Local validation for email and password presence
        const newErrors: { email?: string; password?: string; auth?: string } = {};
        if (!email) {
            newErrors.email = 'Email is required';
        }
        if (!password) {
            newErrors.password = 'Password is required';
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            return;
        }

        // Clear any stale local data to ensure full isolation (Bug #2)
        localStorage.clear();
        sessionStorage.clear();

        setIsLoading(true);
        setErrors({}); // Clear previous errors

        try {
            const response = await fetch('http://localhost:5000/api/auth/login', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ email, password, role }), // Role Isolation
            });

            const data = await response.json();

            if (response.ok) {
                // Persist user identity so profile page can use real data
                setAuthUser({
                    fullName: data.fullName || '',
                    email: data.email || email,
                    token: data.accessToken,
                    role: data.role || 'candidate',
                    _id: data._id,
                });
                hydrateProfileFromAuth();
                login(data.accessToken);

                // Redirect URL Binding logic (Ticket #18)
                const pendingRaw = sessionStorage.getItem('pendingRedirect');
                if (pendingRaw) {
                    try {
                        const pending = JSON.parse(pendingRaw);
                        if (pending.userId === data._id && pending.role === data.role) {
                            window.location.hash = pending.url;
                            sessionStorage.removeItem('pendingRedirect');
                            return; // Follow redirect URL specifically bound to user
                        }
                    } catch (e) { }
                    sessionStorage.removeItem('pendingRedirect'); // discard on new session creation logic
                }

                // Smart route: if onboarding not complete, send to confirmation
                const profile = getProfile();
                if (!profile.onboardingDone) {
                    window.location.hash = '#/users/Cofirmation-Page';
                } else {
                    window.location.hash = '#/candidate/dashboard';
                }
            } else {
                if (data.lockedUntil) {
                    const msLeft = new Date(data.lockedUntil).getTime() - Date.now();
                    setLockoutTimer(Math.max(0, Math.ceil(msLeft / 1000)));
                }
                setErrors({ auth: data.message || 'Invalid credentials' });
            }
        } catch (err) {
            setErrors({ auth: 'Server unreachable. Try again later.' });
        } finally {
            setIsLoading(false);
        }
    };

    const isPasswordValid = isPasswordValidComplete(password);
    const canSubmit = email && isPasswordValid;

    return (
        <div className="login-page">
            {/* Left side: Branding/Hero */}
            <div className="login-sidebar">
                <div className="sidebar-content">
                    <div className="logo" onClick={() => window.location.hash = 'home'} style={{ cursor: 'pointer' }}>
                        <div className="logo-icon-container">
                            <Layers className="logo-icon" color="white" />
                        </div>
                        <span className="logo-text text-white">HireSync</span>
                    </div>

                    <h1 className="sidebar-title">
                        Your next opportunity<br />
                        starts here
                    </h1>

                    <p className="sidebar-subtitle">
                        Join thousands of professionals finding their dream roles through intelligent matching.
                    </p>

                    <div className="feature-list">
                        <div className="feature-item">
                            <div className="feature-icon-wrapper blue">
                                <div className="inner-dot"></div>
                            </div>
                            <span>AI-powered matching</span>
                        </div>
                        <div className="feature-item">
                            <div className="feature-icon-wrapper purple">
                                <div className="inner-pulse"></div>
                            </div>
                            <span>Real-time tracking</span>
                        </div>
                        <div className="feature-item">
                            <div className="feature-icon-wrapper green">
                                <div className="inner-check"></div>
                            </div>
                            <span>Skill-based hiring</span>
                        </div>
                    </div>
                </div>

                <div className="sidebar-footer">
                    &copy; {new Date().getFullYear()} HireSync. All rights reserved.
                </div>
            </div>

            {/* Right side: Login Form */}
            <div className="login-main">
                <div className="login-form-container">
                    <div className="login-header">
                        <span className={`portal-badge ${role}`}>{role === 'candidate' ? 'Candidate Portal' : 'Recruiter Portal'}</span>
                        <h2>Welcome Back</h2>
                        <p>Please enter your details to sign in</p>
                    </div>

                    {/* Role Toggle */}
                    <div className="role-toggle">
                        <button
                            type="button"
                            className={`toggle-btn ${role === 'candidate' ? 'active' : ''}`}
                            onClick={() => setRole('candidate')}
                        >
                            Candidate
                        </button>
                        <button
                            type="button"
                            className={`toggle-btn ${role === 'recruiter' ? 'active' : ''}`}
                            onClick={() => setRole('recruiter')}
                        >
                            Recruiter
                        </button>
                    </div>

                    <form className="login-form" onSubmit={handleSubmit}>
                        {errors.auth && (
                            <div className="error-banner">
                                {errors.auth}
                            </div>
                        )}

                        <div className="form-group">
                            <label htmlFor="email">Email address</label>
                            <input
                                type="email"
                                id="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder={role === 'candidate' ? 'candidate@example.com' : 'employer@company.com'}
                                className={errors.email ? 'input-error' : ''}
                                disabled={isLoading}
                            />
                            {errors.email && <span className="error-text">{errors.email}</span>}
                        </div>

                        <div className="form-group">
                            <div className="password-header">
                                <label htmlFor="password">Password</label>
                                <a href={`#/forgot-password?role=${role}`} className="forgot-link">Forgot Password?</a>
                            </div>
                            <div className="password-input-wrapper">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    id="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    onFocus={() => setPasswordFocused(true)}
                                    onBlur={() => setPasswordFocused(false)}
                                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                    className={errors.password ? 'input-error' : ''}
                                    disabled={isLoading}
                                />
                                <button
                                    type="button"
                                    className="toggle-password"
                                    onClick={() => setShowPassword(!showPassword)}
                                    disabled={isLoading}
                                >
                                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                </button>
                            </div>
                            <PasswordChecklist
                                password={password}
                                visible={passwordFocused || (password.length > 0 && !isPasswordValid)}
                            />
                            {errors.password && <span className="error-text">{errors.password}</span>}
                        </div>

                        <button
                            type="submit"
                            className="submit-btn primary-btn block-btn"
                            disabled={isLoading || !canSubmit || (lockoutTimer !== null && lockoutTimer > 0)}
                        >
                            {lockoutTimer && lockoutTimer > 0
                                ? `Locked (${Math.floor(lockoutTimer / 60)}:${(lockoutTimer % 60).toString().padStart(2, '0')})`
                                : isLoading ? 'Signing In...' : 'Sign In'}
                        </button>

                        <div className="divider">
                            <span>OR CONTINUE WITH</span>
                        </div>

                        <button type="button" className="google-btn block-btn" disabled={isLoading}>
                            <svg className="google-icon" viewBox="0 0 24 24" width="20" height="20">
                                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                            </svg>
                            Google
                        </button>

                        <div className="auth-footer">
                            Don't have an account? <a href={`#/#register?role=${role}`} className="auth-link">Create an account</a>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;

import { useState, useRef, useEffect, useCallback } from 'react';
import { Layers, ShieldCheck, Gauge, Headset, Clock, RefreshCw, AlertCircle, CheckCircle2 } from 'lucide-react';
import { setAuthUser, hydrateProfileFromAuth, getProfile } from '../utils/profileStore';
import './OTP.css';
import './portalBadge.css';

const OTP_VALIDITY_SECONDS = 5 * 60; // 5 minutes, matching backend
const RESEND_COOLDOWN_SECONDS = 60;

const OTP = () => {
    const [otp, setOtp] = useState(['', '', '', '', '', '']);
    const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

    // Countdown timer for OTP expiry (5 min)
    const [timeLeft, setTimeLeft] = useState(OTP_VALIDITY_SECONDS);
    const [isExpired, setIsExpired] = useState(false);

    // Resend cooldown (60 sec)
    const [resendCooldown, setResendCooldown] = useState(RESEND_COOLDOWN_SECONDS);
    const [canResend, setCanResend] = useState(false);
    const [isResending, setIsResending] = useState(false);

    // Form state
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');

    const email = sessionStorage.getItem('registeredEmail') || 'your email';
    const role = sessionStorage.getItem('registeredRole') || 'candidate';

    // ÔöÇÔöÇ OTP Expiry Countdown ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    useEffect(() => {
        window.scrollTo(0, 0);
        inputRefs.current[0]?.focus();
    }, []);

    useEffect(() => {
        if (timeLeft <= 0) {
            setIsExpired(true);
            return;
        }
        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    setIsExpired(true);
                    clearInterval(timer);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
        return () => clearInterval(timer);
    }, [timeLeft]);

    // ÔöÇÔöÇ Resend Cooldown Countdown ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    useEffect(() => {
        if (resendCooldown <= 0) {
            setCanResend(true);
            return;
        }
        setCanResend(false);
        const timer = setInterval(() => {
            setResendCooldown(prev => {
                if (prev <= 1) {
                    setCanResend(true);
                    clearInterval(timer);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
        return () => clearInterval(timer);
    }, [resendCooldown]);

    const formatTime = (seconds: number) => {
        const m = Math.floor(seconds / 60);
        const s = seconds % 60;
        return `${m}:${s.toString().padStart(2, '0')}`;
    };

    // ÔöÇÔöÇ OTP Input Handlers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleChange = (index: number, value: string) => {
        if (value && !/^\d+$/.test(value)) return;
        const newOtp = [...otp];
        newOtp[index] = value.slice(-1); // only last char
        setOtp(newOtp);
        setError('');
        if (value && index < 5) {
            inputRefs.current[index + 1]?.focus();
        }
    };

    const handleKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Backspace' && !otp[index] && index > 0) {
            inputRefs.current[index - 1]?.focus();
        }
    };

    const handlePaste = (e: React.ClipboardEvent) => {
        e.preventDefault();
        const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
        if (!pasted) return;
        const newOtp = [...otp];
        pasted.split('').forEach((char, i) => { newOtp[i] = char; });
        setOtp(newOtp);
        const nextIndex = Math.min(pasted.length, 5);
        inputRefs.current[nextIndex]?.focus();
    };

    // ÔöÇÔöÇ Resend OTP ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleResend = useCallback(async () => {
        if (!canResend || isResending) return;
        setIsResending(true);
        setError('');
        setSuccessMessage('');
        try {
            const response = await fetch('http://localhost:5000/api/auth/register', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    fullName: 'resend', // backend re-sends OTP for unverified users
                    email,
                    password: 'resend-trigger',
                    role: role,
                }),
            });
            const data = await response.json();
            // The register endpoint returns 200 for "unverified user, new OTP sent"
            if (response.ok || response.status === 200) {
                setSuccessMessage('A new OTP has been sent to your email!');
                setTimeLeft(OTP_VALIDITY_SECONDS); // reset expiry timer
                setIsExpired(false);
                setOtp(['', '', '', '', '', '']);
                setResendCooldown(RESEND_COOLDOWN_SECONDS); // restart cooldown
                setTimeout(() => setSuccessMessage(''), 4000);
            } else {
                setError(data.message || 'Failed to resend OTP. Please try again.');
            }
        } catch {
            setError('Could not connect to the server. Please try again.');
        } finally {
            setIsResending(false);
        }
    }, [canResend, isResending, email]);

    // ÔöÇÔöÇ Submit OTP ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        const otpCode = otp.join('');
        if (otpCode.length !== 6) {
            setError('Please enter all 6 digits of your OTP.');
            return;
        }

        if (isExpired) {
            setError('Your OTP has expired. Please request a new one.');
            return;
        }

        const storedEmail = sessionStorage.getItem('registeredEmail');
        if (!storedEmail) {
            setError('Session expired. Please register again.');
            setTimeout(() => {
                window.location.hash = '#/#register';
                window.dispatchEvent(new HashChangeEvent('hashchange'));
            }, 2000);
            return;
        }

        setIsLoading(true);
        try {
            const response = await fetch('http://localhost:5000/api/auth/verify-otp', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email: storedEmail, otp: otpCode, role: role }),
            });

            const data = await response.json();

            if (response.ok) {
                // Save user identity to profileStore (used by profile page)
                setAuthUser({
                    fullName: data.fullName || '',
                    email: data.email || storedEmail,
                    token: data.accessToken,
                    role: data.role || 'candidate',
                    _id: data._id,
                });
                hydrateProfileFromAuth();
                sessionStorage.removeItem('registeredEmail');

                // Smart routing: new user ÔåÆ onboarding, returning user ÔåÆ dashboard
                const profile = getProfile();
                const isNewUser = !profile.onboardingDone;
                setSuccessMessage(isNewUser ? 'Verified! Setting up your profile...' : 'Verified! Redirecting to dashboard...');
                setTimeout(() => {
                    if (isNewUser) {
                        window.location.hash = '#/users/Cofirmation-Page';
                    } else {
                        window.location.hash = '#/candidate/dashboard';
                    }
                    window.dispatchEvent(new HashChangeEvent('hashchange'));
                }, 800);
            } else {
                setError(data.message || 'Invalid OTP. Please check and try again.');
                // Clear inputs for re-entry
                setOtp(['', '', '', '', '', '']);
                setTimeout(() => inputRefs.current[0]?.focus(), 50);
            }
        } catch {
            setError('Could not connect to the server. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    const isOtpComplete = otp.every(d => d !== '');

    return (
        <div className="otp-container">
            <div className="otp-left">
                <div>
                    <div className="otp-logo animate-item delay-1">
                        <div className="logo-icon-wrapper">
                            <Layers size={22} className="logo-icon-inner" />
                        </div>
                        <span className="otp-logo-text">HireSync</span>
                    </div>

                    <div className="otp-content">
                        <h1 className="otp-title animate-item delay-2">Next-gen Hiring Platform</h1>
                        <p className="otp-subtitle animate-item delay-3">
                            Streamline your recruitment process with AI-driven insights and verified talent pools.
                        </p>

                        <div className="otp-features">
                            <div className="feature-row animate-item delay-4">
                                <div className="feature-icon-container">
                                    <ShieldCheck size={20} />
                                </div>
                                <div className="feature-text">
                                    <div className="feature-title">Identity Verification</div>
                                    <div className="feature-desc">Secure 2FA for all talent interactions</div>
                                </div>
                            </div>
                            <div className="feature-row animate-item delay-5">
                                <div className="feature-icon-container">
                                    <Gauge size={20} />
                                </div>
                                <div className="feature-text">
                                    <div className="feature-title">Rapid Onboarding</div>
                                    <div className="feature-desc">Get teams ready in minutes, not days</div>
                                </div>
                            </div>
                            <div className="feature-row animate-item delay-6">
                                <div className="feature-icon-container">
                                    <Headset size={20} />
                                </div>
                                <div className="feature-text">
                                    <div className="feature-title">24/7 Priority Support</div>
                                    <div className="feature-desc">Expert help whenever you need it</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="otp-footer animate-item delay-7">
                    &copy; 2026 HireSync Inc. All rights reserved.
                </div>
            </div>

            <div className="otp-right">
                <div className="otp-form-wrapper">
                    <span className={`portal-badge ${role}`} style={{ marginBottom: '16px' }}>{role === 'candidate' ? 'Candidate Portal' : 'Recruiter Portal'}</span>

                    {/* Validity Timer Badge */}
                    <div className={`otp-timer-badge ${isExpired ? 'expired' : timeLeft <= 60 ? 'urgent' : ''}`}>
                        <Clock size={14} />
                        {isExpired
                            ? 'OTP Expired'
                            : `OTP valid for ${formatTime(timeLeft)}`}
                    </div>

                    <h2 className="otp-form-head">Verify Your Identity</h2>
                    <p className="otp-form-subhead">
                        We've sent a 6-digit code to your email address<br />
                        <strong>{email}</strong>. Please enter it below.
                    </p>

                    {/* Inline error / success messages */}
                    {error && (
                        <div className="otp-message otp-message--error">
                            <AlertCircle size={16} />
                            <span>{error}</span>
                        </div>
                    )}
                    {successMessage && (
                        <div className="otp-message otp-message--success">
                            <CheckCircle2 size={16} />
                            <span>{successMessage}</span>
                        </div>
                    )}

                    <form className="otp-form" onSubmit={handleSubmit}>
                        <div className="otp-inputs">
                            {otp.map((digit, index) => (
                                <input
                                    key={index}
                                    type="text"
                                    inputMode="numeric"
                                    maxLength={1}
                                    value={digit}
                                    onChange={(e) => handleChange(index, e.target.value)}
                                    onKeyDown={(e) => handleKeyDown(index, e)}
                                    onPaste={handlePaste}
                                    ref={(el) => { inputRefs.current[index] = el; }}
                                    className={`otp-input-box ${digit ? 'filled' : ''} ${isExpired ? 'expired' : ''}`}
                                    placeholder="ÔÇó"
                                    disabled={isLoading || !!successMessage}
                                    autoComplete="one-time-code"
                                />
                            ))}
                        </div>

                        <button
                            type="submit"
                            className="otp-submit-btn"
                            disabled={isLoading || !isOtpComplete || isExpired || !!successMessage}
                            style={{ opacity: (isLoading || !isOtpComplete || isExpired) ? 0.7 : 1 }}
                        >
                            {isLoading ? (
                                <span className="otp-btn-loading">
                                    <span className="otp-spinner" />
                                    Verifying...
                                </span>
                            ) : 'Verify & Proceed'}
                        </button>
                    </form>

                    <div className="resend-section">
                        <p className="resend-text">
                            Didn't receive the code?{' '}
                            <button
                                className={`resend-link-btn ${!canResend ? 'disabled' : ''}`}
                                onClick={handleResend}
                                disabled={!canResend || isResending}
                                type="button"
                            >
                                {isResending ? 'Sending...' : 'Resend Code'}
                            </button>
                        </p>
                        {!canResend && (
                            <div className="resend-badge">
                                <RefreshCw size={12} />
                                RESEND IN {formatTime(resendCooldown)}
                            </div>
                        )}
                    </div>

                    <div className="otp-bottom-links">
                        <a href="#">HELP CENTER</a>
                        <a href="#">PRIVACY POLICY</a>
                        <a href="#">TERMS</a>
                    </div>
                </div>
            </div>
        </div>
    );
};

