import { useState, useEffect, useCallback, useRef } from 'react';
import {
    AlertTriangle, ShieldAlert, Clock, ChevronRight,
    Send, CheckCircle, VideoOff, MicOff
} from 'lucide-react';
import { useProctoring } from '../../../hooks/useProctoring';
import { useAntiCheat } from '../../../hooks/useAntiCheat';
import { useSoundDetection } from '../../../hooks/useSoundDetection';
import { useAssessmentTimer } from '../../../hooks/useAssessmentTimer';
import { generateAssessmentQuestions, evaluateAssessment } from '../../../services/geminiAssessment';
import type { Question, ViolationType, Violation, AssessmentState } from '../../../types/assessment.types';
import './Assessment.css';

interface Props { onNavigate: (p: string) => void; }

const Assessment = ({ onNavigate }: Props) => {
    // ÔöÇÔöÇ Pre-flight Checks ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const permissionsStr = sessionStorage.getItem('permissionsGranted');
    const roleId = sessionStorage.getItem('sz_career');
    const expId = sessionStorage.getItem('sz_experience');

    const [isAuthorized, setIsAuthorized] = useState<boolean | null>(null);

    // ÔöÇÔöÇ State Management ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const [state, setState] = useState<AssessmentState>({
        questions: [],
        currentIndex: 0,
        answers: new Map(),
        markedForReview: new Set(),
        questionTimer: 40,
        totalTimeElapsed: 0,
        violations: [],
        warningCount: 0,
        status: 'loading',
        isFullscreen: false
    });

    const [warningModalMsg, setWarningModalMsg] = useState<string | null>(null);

    // Need refs for latest state values inside intervals/callbacks
    const stateRef = useRef(state);
    const lastViolTime = useRef(0);
    useEffect(() => { stateRef.current = state; }, [state]);

    // ÔöÇÔöÇ Initialize ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    useEffect(() => {
        // Validation
        if (!permissionsStr || permissionsStr !== 'true' || !roleId || !expId) {
            onNavigate('skill-zone/instructions');
            return;
        }

        const todayStr = new Date().toISOString().split('T')[0];
        const storedDate = localStorage.getItem('sz_attempts_date');
        const count = parseInt(localStorage.getItem('sz_attempts_count') || '0');

        if (storedDate === todayStr && count >= 3) {
            alert(`You have used all 3 assessment attempts for today. Please wait until tomorrow.`);
            onNavigate('skill-zone');
            return;
        }

        setIsAuthorized(true);

        // Load or Generate Questions
        const loadAssessment = async () => {
            try {
                // Check sessionStorage for recovery
                const recoveredStr = sessionStorage.getItem('sz_in_progress');
                if (recoveredStr) {
                    const parsed = JSON.parse(recoveredStr);
                    // Rehydrate Map/Set objects
                    parsed.answers = new Map(Object.entries(parsed.answers).map(([k, v]) => [Number(k), v]));
                    parsed.markedForReview = new Set(parsed.markedForReview);
                    setState(parsed);
                    return;
                }

                // Record attempt start
                const currentCount = (storedDate === todayStr) ? count : 0;
                localStorage.setItem('sz_attempts_date', todayStr);
                localStorage.setItem('sz_attempts_count', (currentCount + 1).toString());

                const qs = await generateAssessmentQuestions(roleId, expId);
                setState(prev => ({
                    ...prev,
                    questions: qs,
                    status: 'active'
                }));
            } catch (err) {
                console.error("Initialization error:", err);
                setWarningModalMsg("Failed to connect to AI engine. Please check your connection and try again.");
            }
        };

        if (isAuthorized) {
            loadAssessment();

            // Enforce fullscreen immediately when authorized
            if (!document.fullscreenElement) {
                document.documentElement.requestFullscreen().catch(console.warn);
            }
        }
    }, [isAuthorized, roleId, expId, permissionsStr, onNavigate]);

    // ÔöÇÔöÇ Hooks ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleViolation = useCallback((type: ViolationType, details = '') => {
        if (stateRef.current.status !== 'active') return;

        const now = Date.now();
        // Prevent double triggers within 2 seconds (e.g. blur + visibilitychange triggering at once)
        if (now - lastViolTime.current < 2000) return;
        lastViolTime.current = now;

        const viol: Violation = {
            type,
            timestamp: new Date(),
            questionIndex: stateRef.current.currentIndex,
            details
        };

        const currentWarnings = stateRef.current.warningCount;
        const nextCount = currentWarnings + 1;

        setState(prev => {
            const updated = {
                ...prev,
                violations: [...prev.violations, viol],
                warningCount: nextCount
            };
            return updated;
        });

        if (nextCount >= 3) {
            setWarningModalMsg("Max violations reached (3/3). Your assessment will be automatically submitted.");
        } else {
            let msg = '';
            if (type === 'TAB_SWITCH' || type === 'WINDOW_BLUR') msg = 'You navigated away from the exam window.';
            else if (type === 'FULLSCREEN_EXIT') msg = 'You exited full-screen mode.';
            else if (type === 'NOISE_DETECTED') msg = 'Significant background noise detected.';
            else msg = type;

            setWarningModalMsg(`Proctoring Alert: ${msg} Continuous violations result in termination. Warning ${nextCount}/3`);
        }
    }, []);

    useAntiCheat({
        isActive: state.status === 'active',
        onViolation: handleViolation
    });

    const { videoRef, requestCamera, cameraAllowed } = useProctoring({
        isActive: state.status === 'active',
        onViolation: handleViolation,
        intervalMs: 12000 // every 12s frame capture
    });

    const { requestAudio, checkNoiseLevel, audioAllowed } = useSoundDetection();

    // Audio tracking interval wrapper
    useEffect(() => {
        if (state.status !== 'active') return;

        const noiseTimer = setInterval(() => {
            if (checkNoiseLevel()) {
                handleViolation('NOISE_DETECTED', 'Background noise exceeded threshold');
            }
        }, 3000);
        return () => clearInterval(noiseTimer);
    }, [state.status, checkNoiseLevel, handleViolation]);

    // Start Camera/Mic streams if not already running
    useEffect(() => {
        if (isAuthorized && state.status === 'active') {
            if (cameraAllowed === null) requestCamera();
            if (audioAllowed === null) requestAudio();
        }
    }, [isAuthorized, state.status, cameraAllowed, audioAllowed, requestCamera, requestAudio]);

    // Block browser back button
    useEffect(() => {
        if (!isAuthorized) return;
        window.history.pushState(null, '', window.location.href);
        const handlePopState = (e: PopStateEvent) => {
            if (stateRef.current.status === 'active') {
                e.preventDefault();
                handleViolation('TAB_SWITCH', 'Attempted to use browser back button');
                window.history.pushState(null, '', window.location.href);
            }
        };
        window.addEventListener('popstate', handlePopState);
        return () => window.removeEventListener('popstate', handlePopState);
    }, [isAuthorized, handleViolation]);

    // Persistent storage saver
    useEffect(() => {
        if (state.status === 'loading' || state.questions.length === 0) return;
        // Don't save if submitted
        if (state.status === 'submitted') {
            sessionStorage.removeItem('sz_in_progress');
            return;
        }

        const toSave = {
            ...state,
            answers: Object.fromEntries(state.answers),
            markedForReview: Array.from(state.markedForReview)
        };
        sessionStorage.setItem('sz_in_progress', JSON.stringify(toSave));
    }, [state]);

    // Timer logic
    const handleTimeUp = useCallback(() => {
        if (stateRef.current.status !== 'active') return;

        setState(prev => {
            if (prev.currentIndex < prev.questions.length - 1) {
                return { ...prev, currentIndex: prev.currentIndex + 1, questionTimer: 40 };
            } else {
                return { ...prev, status: 'submitted' };
            }
        });

        if (stateRef.current.currentIndex === stateRef.current.questions.length - 1) {
            handleFinalSubmit();
        }
    }, []);

    const { questionTimer, totalTimeElapsed, resetQuestionTimer } = useAssessmentTimer({
        initialQuestionTime: 40,
        isActive: state.status === 'active',
        onTimeUp: handleTimeUp
    });

    // ÔöÇÔöÇ Actions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const handleOptionSelect = (idx: number) => {
        setState(prev => {
            const newAnswers = new Map(prev.answers);
            newAnswers.set(prev.currentIndex, idx);
            return { ...prev, answers: newAnswers };
        });
    };

    const handleNext = () => {
        setState(prev => {
            if (prev.currentIndex < prev.questions.length - 1) {
                resetQuestionTimer();
                return { ...prev, currentIndex: prev.currentIndex + 1 };
            }
            return prev;
        });
    };

    const handleFinalSubmit = async () => {
        setState(prev => ({ ...prev, status: 'loading' })); // repurpose loading for eval state

        const latest = stateRef.current; // Grab latest ref immediately

        try {
            // Remove the 7 day cooldown marker (it's handled by daily attempts now)
            localStorage.removeItem('sz_last_attempt');

            const result = await evaluateAssessment(
                latest.questions,
                latest.answers,
                latest.violations,
                totalTimeElapsed,
                roleId || 'Unknown Role'
            );

            // In a real app we'd POST to backend here, e.g.
            // await fetch('/api/assessment/submit', { method: 'POST', body: JSON.stringify(result) });

            // Embed the original questions and user answers for the Result page review
            const finalPayload = {
                ...result,
                paperDetails: {
                    questions: latest.questions,
                    answers: Object.fromEntries(latest.answers)
                }
            };

            sessionStorage.setItem('sz_result', JSON.stringify(finalPayload));
            sessionStorage.removeItem('sz_in_progress');

            // Ensure exit fullscreen
            if (document.fullscreenElement) {
                document.exitFullscreen().catch(() => { });
            }

            onNavigate('skill-zone/result');

        } catch (err) {
            console.error("Evaluation Failed:", err);
            setWarningModalMsg("Failed to generate final report. We saved your answers. Please try again.");
            setState(prev => ({ ...prev, status: 'active' })); // return to active so they can try submit again
        }
    };

    // ÔöÇÔöÇ Render Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    if (!isAuthorized) return null;

    if (state.status === 'loading') {
        return (
            <div className="sz-root" style={{ justifyContent: 'center', alignItems: 'center' }}>
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
                    <div className="sz-spinner" style={{ width: 40, height: 40, borderWidth: 3 }} />
                    <h2 style={{ fontSize: '1.2rem', color: '#fff', fontWeight: 600 }}>
                        {state.questions.length === 0 ? "Generating Adaptive Questions..." : "Evaluating Result..."}
                    </h2>
                    <p style={{ color: '#64748b' }}>Please wait. Do not close this tab.</p>
                </div>
            </div>
        );
    }

    const currentQ: Question | undefined = state.questions[state.currentIndex];
    if (!currentQ) return null; // Safety boundary

    const progressPerc = Math.round(((state.currentIndex + 1) / state.questions.length) * 100);

    return (
        <div className="sz-assess-root">
            {/* Header Strip */}
            <div className="sz-assess-header">
                <div className="sz-h-left">
                    <ShieldAlert size={18} color={state.warningCount > 0 ? "#f59e0b" : "#10b981"} />
                    <span style={{ fontSize: '0.85rem', fontWeight: 600, color: '#e2e8f0' }}>Secure Engine Active</span>
                </div>

                <div className="sz-h-center">
                    <div className="sz-progress-bar">
                        <div className="sz-progress-fill" style={{ width: `${progressPerc}%` }} />
                    </div>
                    <span style={{ fontSize: '0.8rem', color: '#94a3b8', fontWeight: 500 }}>
                        Question {state.currentIndex + 1} of {state.questions.length}
                    </span>
                </div>

                <div className="sz-h-right">
                    <div className={`sz-timer ${questionTimer <= 10 ? 'danger' : ''}`}>
                        <Clock size={16} /> 00:{questionTimer < 10 ? `0${questionTimer}` : questionTimer}
                    </div>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="sz-assess-main">
                {/* Left Panel: Question */}
                <div className="sz-q-panel">
                    <div className="sz-q-meta">
                        <span className="sz-q-badge" style={{ background: currentQ.difficulty === 'hard' ? 'rgba(239,68,68,0.1)' : currentQ.difficulty === 'medium' ? 'rgba(245,158,11,0.1)' : 'rgba(16,185,129,0.1)', color: currentQ.difficulty === 'hard' ? '#ef4444' : currentQ.difficulty === 'medium' ? '#f59e0b' : '#10b981' }}>
                            {currentQ.difficulty.toUpperCase()}
                        </span>
                        <span className="sz-q-badge" style={{ background: 'rgba(59,130,246,0.1)', color: '#3b82f6' }}>
                            {currentQ.topic}
                        </span>
                    </div>

                    <h2 className="sz-q-text">{currentQ.question}</h2>

                    {currentQ.type === 'code' && currentQ.code && (
                        <div className="sz-q-code">
                            <pre><code>{currentQ.code}</code></pre>
                            <span className="sz-q-lang">{currentQ.language || 'Code Snippet'}</span>
                        </div>
                    )}
                </div>

                {/* Right Panel: Options */}
                <div className="sz-opt-panel">
                    {currentQ.options.map((opt, idx) => {
                        const isSelected = state.answers.get(state.currentIndex) === idx;
                        return (
                            <button
                                key={idx}
                                className={`sz-opt-btn ${isSelected ? 'selected' : ''}`}
                                onClick={() => handleOptionSelect(idx)}
                            >
                                <span className="sz-opt-letter">{String.fromCharCode(65 + idx)}</span>
                                <span className="sz-opt-text">{opt}</span>
                                {isSelected && <CheckCircle size={18} className="sz-opt-check" />}
                            </button>
                        );
                    })}
                </div>

                {/* Secure Anti-AI Warning */}
                <div style={{ marginTop: '2.5rem', gridColumn: '1 / -1', textAlign: 'center', fontSize: '0.85rem', color: '#94a3b8', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '1.5rem', opacity: 0.8 }}>
                    If a user captures the exam screen and attempts to retrieve answers using external AI tools or image recognition systems, the system may detect suspicious behavior and block the attempt.
                </div>
            </div>

            {/* Footer Strip */}
            <div className="sz-assess-footer">
                <div className="sz-f-streams">
                    <div className="sz-stream-box">
                        <video ref={videoRef} autoPlay playsInline muted />
                        {!cameraAllowed && <div className="sz-stream-err"><VideoOff size={16} /></div>}
                    </div>
                    <div className="sz-stream-box audio-indicator">
                        <div className="sz-mic-levels">
                            <MicOff size={14} color="#64748b" style={{ position: 'absolute', zIndex: 1 }} />
                            <div className="sz-mic-fill" />
                        </div>
                        <span style={{ fontSize: '0.65rem', color: '#64748b' }}>Recording</span>
                    </div>
                </div>

                <div className="sz-f-actions">
                    {state.currentIndex < state.questions.length - 1 ? (
                        <button
                            className={`sz-btn-primary ${!state.answers.has(state.currentIndex) ? 'disabled' : ''}`}
                            onClick={handleNext}
                            disabled={!state.answers.has(state.currentIndex)}
                        >
                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', pointerEvents: 'none' }}>
                                Next Question <ChevronRight size={16} />
                            </span>
                        </button>
                    ) : (
                        <button
                            className={`sz-btn-primary sz-btn-start ${!state.answers.has(state.currentIndex) ? 'disabled' : ''}`}
                            onClick={handleFinalSubmit}
                            disabled={!state.answers.has(state.currentIndex)}
                        >
                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', pointerEvents: 'none' }}>
                                Submit Assessment <Send size={16} />
                            </span>
                        </button>
                    )}
                </div>
            </div>

            {/* Warning Overlay */}
            {warningModalMsg && (
                <div className="sz-warning-overlay">
                    <div className="sz-warning-modal">
                        <div className="sz-warn-icon"><AlertTriangle size={32} /></div>
                        <h3>Proctoring Violation</h3>
                        <p>{warningModalMsg}</p>
                        <button className="sz-btn-primary sz-btn-alert" onClick={() => {
                            setWarningModalMsg(null);
                            if (state.warningCount >= 3) {
                                handleFinalSubmit();
                            } else {
                                if (!document.fullscreenElement) {
                                    document.documentElement.requestFullscreen().catch(() => { });
                                }
                            }
                        }}>
                            Acknowledge & Continue
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Assessment;

import { useState, useEffect, useRef } from 'react';
import { Shield, Camera, Mic, Maximize, CheckCircle2, AlertCircle, Cpu } from 'lucide-react';
import CandidateHeader from '../../../components/CandidateHeader';
import { ParticleCanvas } from './ParticleCanvas';
import { testGeminiConnection } from '../../../services/geminiAssessment';

interface Props { onNavigate: (p: string) => void; }

const Permissions = ({ onNavigate }: Props) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [cameraStatus, setCameraStatus] = useState<'pending' | 'checking' | 'granted' | 'denied'>('pending');
    const [micStatus, setMicStatus] = useState<'pending' | 'checking' | 'granted' | 'denied'>('pending');
    const [screenStatus, setScreenStatus] = useState<'pending' | 'granted' | 'denied'>('pending');
    const [apiStatus, setApiStatus] = useState<'pending' | 'checking' | 'granted' | 'denied'>('pending');

    const [noiseLevel, setNoiseLevel] = useState(0);

    // Guard route
    useEffect(() => {
        const savedCareerId = sessionStorage.getItem('sz_career');
        const savedExpId = sessionStorage.getItem('sz_experience');
        if (!savedCareerId || !savedExpId) {
            onNavigate('skill-zone');
        }
    }, [onNavigate]);

    const requestCamera = async () => {
        setCameraStatus('checking');
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
            setCameraStatus('granted');
        } catch (err) {
            console.error(err);
            setCameraStatus('denied');
        }
    };

    const requestMic = async () => {
        setMicStatus('checking');
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

            // Simple visualizer setup
            const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
            const analyser = audioCtx.createAnalyser();
            const source = audioCtx.createMediaStreamSource(stream);
            source.connect(analyser);
            analyser.fftSize = 256;
            const bufferLength = analyser.frequencyBinCount;
            const dataArray = new Uint8Array(bufferLength);

            const updateNoise = () => {
                if (stream.active) {
                    analyser.getByteFrequencyData(dataArray);
                    const avg = dataArray.reduce((acc, val) => acc + val, 0) / bufferLength;
                    setNoiseLevel(Math.min(100, (avg / 128) * 100)); // Normalize approx
                    requestAnimationFrame(updateNoise);
                }
            };
            updateNoise();

            setMicStatus('granted');
        } catch (err) {
            console.error(err);
            setMicStatus('denied');
        }
    };

    const requestFullscreen = async () => {
        try {
            if (!document.fullscreenElement) {
                await document.documentElement.requestFullscreen();
            }
            setScreenStatus('granted');
        } catch (err) {
            console.error(err);
            setScreenStatus('denied');
        }
    };

    const checkApi = async () => {
        setApiStatus('checking');
        const isWorking = await testGeminiConnection();
        setApiStatus(isWorking ? 'granted' : 'denied');
    };

    // Cleanup streams on unmount
    useEffect(() => {
        return () => {
            if (videoRef.current && videoRef.current.srcObject) {
                const stream = videoRef.current.srcObject as MediaStream;
                stream.getTracks().forEach(t => t.stop());
            }
        };
    }, []);

    const allReady = cameraStatus === 'granted' && micStatus === 'granted' && screenStatus === 'granted' && apiStatus === 'granted';

    const handleStart = () => {
        if (!allReady) return;
        sessionStorage.setItem('permissionsGranted', 'true');
        onNavigate('skill-zone/assessment');
    };

    const renderStatusIcon = (status: string) => {
        if (status === 'granted') return <CheckCircle2 size={18} color="#10b981" />;
        if (status === 'denied') return <AlertCircle size={18} color="#ef4444" />;
        if (status === 'checking') return <span className="sz-spinner" style={{ width: 14, height: 14, borderWidth: 1.5 }} />;
        return <AlertCircle size={18} color="#f59e0b" />;
    };

    return (
        <div className="sz-root">
            <ParticleCanvas />
            <div className="sz-glow sz-glow1" />
            <div className="sz-glow sz-glow2" />
            <CandidateHeader activePage="skill-zone" onNavigate={onNavigate} />

            <div className="sz-content">
                <div className="sz-steps-indicator">
                    {[1, 2, 3, 4, 5].map(s => (
                        <div key={s} className="sz-step-item" style={{ flex: '1 1 0' }}>
                            <div className={`sz-step-dot ${5 >= s ? 'active' : ''} ${5 > s ? 'done' : ''}`}>
                                {5 > s ? 'Ô£ô' : s}
                            </div>
                            <span className={`sz-step-label ${5 === s ? 'active' : ''}`} style={{ fontSize: '0.7rem' }}>
                                {s === 1 ? 'Career' : s === 2 ? 'Experience' : s === 3 ? 'Resume' : s === 4 ? 'Rules' : 'Setup'}
                            </span>
                            {s < 5 && <div className={`sz-step-line ${5 > s ? 'done' : ''}`} />}
                        </div>
                    ))}
                </div>

                <div className="sz-step-panel sz-step4" style={{ maxWidth: 860 }}>
                    <div className="sz-hero-badge"><Shield size={13} /> System Integrity Check</div>
                    <h1 className="sz-title">Environment <span className="sz-accent" style={{ background: 'linear-gradient(135deg, #10b981, #06b6d4)' }}>Permissions</span></h1>
                    <p className="sz-subtitle" style={{ marginBottom: '2rem' }}>We need access to your camera, microphone, and a secure fullscreen view to ensure academic integrity.</p>

                    <div style={{ display: 'grid', gridTemplateColumns: 'minmax(300px, 1fr) 280px', gap: '2rem', width: '100%', alignItems: 'start' }}>

                        {/* Permissions List */}
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {/* API Check */}
                            <div style={{ background: 'rgba(20,27,43,0.7)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '14px', padding: '1.25rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                    <div style={{ width: 40, height: 40, background: 'rgba(239,68,68,0.1)', color: '#ef4444', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Cpu size={20} />
                                    </div>
                                    <div>
                                        <h4 style={{ color: '#fff', fontSize: '0.95rem', marginBottom: '0.1rem' }}>AI Engine</h4>
                                        <p style={{ color: '#64748b', fontSize: '0.8rem' }}>Verifies connection to Gemini AI.</p>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    {renderStatusIcon(apiStatus)}
                                    {apiStatus !== 'granted' && (
                                        <button onClick={checkApi} style={{ background: 'rgba(239,68,68,0.15)', color: '#ef4444', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                            {apiStatus === 'denied' ? 'Retry' : 'Test'}
                                        </button>
                                    )}
                                </div>
                            </div>

                            {/* Camera */}
                            <div style={{ background: 'rgba(20,27,43,0.7)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '14px', padding: '1.25rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                    <div style={{ width: 40, height: 40, background: 'rgba(59,130,246,0.1)', color: '#3b82f6', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Camera size={20} />
                                    </div>
                                    <div>
                                        <h4 style={{ color: '#fff', fontSize: '0.95rem', marginBottom: '0.1rem' }}>Webcam Access</h4>
                                        <p style={{ color: '#64748b', fontSize: '0.8rem' }}>Required for live AI face proctoring.</p>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    {renderStatusIcon(cameraStatus)}
                                    {cameraStatus !== 'granted' && (
                                        <button onClick={requestCamera} style={{ background: 'rgba(59,130,246,0.15)', color: '#3b82f6', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                            {cameraStatus === 'denied' ? 'Retry' : 'Allow'}
                                        </button>
                                    )}
                                </div>
                            </div>

                            {/* Mic */}
                            <div style={{ background: 'rgba(20,27,43,0.7)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '14px', padding: '1.25rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                    <div style={{ width: 40, height: 40, background: 'rgba(139,92,246,0.1)', color: '#8b5cf6', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Mic size={20} />
                                    </div>
                                    <div>
                                        <h4 style={{ color: '#fff', fontSize: '0.95rem', marginBottom: '0.1rem' }}>Microphone Access</h4>
                                        <p style={{ color: '#64748b', fontSize: '0.8rem' }}>Detects unauthorized background presence.</p>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    {renderStatusIcon(micStatus)}
                                    {micStatus !== 'granted' && (
                                        <button onClick={requestMic} style={{ background: 'rgba(139,92,246,0.15)', color: '#8b5cf6', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                            {micStatus === 'denied' ? 'Retry' : 'Allow'}
                                        </button>
                                    )}
                                </div>
                            </div>

                            {/* Fullscreen */}
                            <div style={{ background: 'rgba(20,27,43,0.7)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '14px', padding: '1.25rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                    <div style={{ width: 40, height: 40, background: 'rgba(16,185,129,0.1)', color: '#10b981', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Maximize size={20} />
                                    </div>
                                    <div>
                                        <h4 style={{ color: '#fff', fontSize: '0.95rem', marginBottom: '0.1rem' }}>Secure Fullscreen</h4>
                                        <p style={{ color: '#64748b', fontSize: '0.8rem' }}>Locks environment to prevent tab switching.</p>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    {renderStatusIcon(screenStatus)}
                                    {screenStatus !== 'granted' && (
                                        <button onClick={requestFullscreen} style={{ background: 'rgba(16,185,129,0.15)', color: '#10b981', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '6px', fontSize: '0.8rem', fontWeight: 600, cursor: 'pointer' }}>
                                            {screenStatus === 'denied' ? 'Retry' : 'Enter'}
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>

                        {/* Preview panel */}
                        <div style={{ background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: '14px', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                            <div style={{ height: 200, background: '#000', position: 'relative' }}>
                                <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: cameraStatus === 'granted' ? 1 : 0.2 }} />
                                {cameraStatus !== 'granted' && (
                                    <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#64748b', fontSize: '0.8rem' }}>
                                        Camera Preview
                                    </div>
                                )}
                            </div>
                            <div style={{ padding: '1rem', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
                                <div style={{ fontSize: '0.75rem', color: '#94a3b8', marginBottom: '0.5rem', display: 'flex', justifyContent: 'space-between' }}>
                                    <span>Mic Level</span>
                                    <span>{micStatus === 'granted' ? 'Active' : 'Muted'}</span>
                                </div>
                                <div style={{ width: '100%', height: '6px', background: 'rgba(255,255,255,0.1)', borderRadius: '4px', overflow: 'hidden' }}>
                                    <div style={{ width: `${noiseLevel}%`, height: '100%', background: noiseLevel > 80 ? '#ef4444' : '#10b981', transition: 'width 0.1s ease-out, background 0.3s' }} />
                                </div>
                            </div>
                        </div>

                    </div>

                    <div style={{ marginTop: '3rem', display: 'flex', gap: '1rem', width: '100%' }}>
                        <button className="sz-back-btn" onClick={() => onNavigate('skill-zone/instructions')} style={{ margin: 0, padding: '0.85rem 2rem', background: 'rgba(255,255,255,0.05)' }}>
                            Go Back
                        </button>
                        <button
                            className={`sz-btn-primary ${!allReady ? 'disabled' : ''}`}
                            onClick={handleStart}
                            disabled={!allReady}
                            style={{ flex: 1, justifyContent: 'center' }}
                        >
                            Start AI Assessment Engine
                        </button>
                    </div>

                </div>
            </div>
        </div>
    );
};

export default Permissions;

